  1→use std::collections::{BTreeMap, HashMap};
  2→use std::fs::File;
  3→use std::io::{BufRead, BufReader};
  4→use std::path::PathBuf;
  5→
  6→use clap::Parser;
  7→
  8→use ccs_viewer::types::{AgentMeta, Record};
  9→
 10→#[derive(Parser)]
 11→#[command(
 12→    version,
 13→    about = "Claude Code session JSONL viewer",
 14→    after_help = "\
 15→Output is always in this fixed order regardless of flag order:
 16→  valid (-v) > errors (-e/-E) > skipped (-s) > zero-len (-z) > summary (always last)
 17→
 18→Summary: <total> total files, <valid> valid files with <records> records, <n> zero-len, <n> skipped, <n> errors
 19→  total:    all files found by glob/recursive search
 20→  valid:    files successfully processed (total minus zero-len and skipped)
 21→  records:  total successfully deserialized records (in valid files)
 22→  zero-len: zero-length files
 23→  skipped:  files that failed the first-line sniff test
 24→  errors:   total deserialization failures
 25→
 26→Exit codes:
 27→  0  Success (default, even with deserialization errors)
 28→  1  Tool failure (bad args, can't open file, no files match)
 29→  2  Deserialization errors present (only with --strict)"
 30→)]
 31→struct Cli {
 32→    /// File or directory glob patterns to process
 33→    #[arg(required = true)]
 34→    patterns: Vec<String>,
 35→
 36→    /// Recursively search directories for matching files
 37→    #[arg(short, long)]
 38→    recursive: bool,
 39→
 40→    /// File glob pattern for recursive mode (repeatable, default: *.jsonl, agent-*.meta.json)
 41→    #[arg(long = "glob")]
 42→    globs: Vec<String>,
 43→
 44→    /// Show valid files (filename + record type counts on two lines)
 45→    #[arg(short, long, help_heading = "Summary detail flags")]
 46→    valid: bool,
 47→
 48→    /// Show error file paths with line numbers
 49→    #[arg(short, long, help_heading = "Summary detail flags")]
 50→    errors: bool,
 51→
 52→    /// Show deduplicated error summary (grouped by message, sorted by count)
 53→    #[arg(short = 'E', long, help_heading = "Summary detail flags")]
 54→    error_summary: bool,
 55→
 56→    /// Show files skipped by the first-line sniff test
 57→    #[arg(short, long, help_heading = "Summary detail flags")]
 58→    skipped: bool,
 59→
 60→    /// Show zero-length files
 61→    #[arg(short, long, help_heading = "Summary detail flags")]
 62→    zero: bool,
 63→
 64→    /// Exit 2 if deserialization errors are present
 65→    #[arg(long)]
 66→    strict: bool,
 67→}
 68→
 69→/// Resolve CLI patterns into a list of file paths.
 70→fn resolve_files(cli: &Cli) -> Vec<PathBuf> {
 71→    let mut files = Vec::new();
 72→
 73→    if cli.recursive {
 74→        let file_globs: Vec<&str> = if cli.globs.is_empty() {
 75→            vec!["*.jsonl", "agent-*.meta.json"]
 76→        } else {
 77→            cli.globs.iter().map(|s| s.as_str()).collect()
 78→        };
 79→
 80→        // Expand positional patterns as directory globs.
 81→        for pattern in &cli.patterns {
 82→            let dirs: Vec<PathBuf> = match glob::glob(pattern) {
 83→                Ok(paths) => paths
 84→                    .filter_map(|p| p.ok())
 85→                    .filter(|p| p.is_dir())
 86→                    .collect(),
 87→                Err(e) => {
 88→                    eprintln!("Bad pattern {pattern:?}: {e}");
 89→                    std::process::exit(1);
 90→                }
 91→            };
 92→            if dirs.is_empty() {
 93→                eprintln!("No directories match {pattern:?}");
 94→                std::process::exit(1);
 95→            }
 96→            for dir in &dirs {
 97→                for fg in &file_globs {
 98→                    let full = format!("{}/**/{fg}", dir.display());
 99→                    match glob::glob(&full) {
100→                        Ok(paths) => {
101→                            for entry in paths.flatten() {
102→                                if entry.is_file() {
103→                                    files.push(entry);
104→                                }
105→                            }
106→                        }
107→                        Err(e) => {
108→                            eprintln!("Bad glob {full:?}: {e}");
109→                            std::process::exit(1);
110→                        }
111→                    }
112→                }
113→            }
114→        }
115→    } else {
116→        let file_globs: Vec<&str> = if cli.globs.is_empty() {
117→            vec!["*.jsonl", "agent-*.meta.json"]
118→        } else {
119→            cli.globs.iter().map(|s| s.as_str()).collect()
120→        };
121→
122→        for pattern in &cli.patterns {
123→            // Check if pattern is a literal directory path first.
124→            let path = PathBuf::from(pattern);
125→            if path.is_dir() {
126→                // Directory: expand file globs inside it (non-recursive).
127→                for fg in &file_globs {
128→                    let full = format!("{}/{fg}", path.display());
129→                    match glob::glob(&full) {
130→                        Ok(paths) => {
131→                            for entry in paths.flatten() {
132→                                if entry.is_file() {
133→                                    files.push(entry);
134→                                }
135→                            }
136→                        }
137→                        Err(e) => {
138→                            eprintln!("Bad glob {full:?}: {e}");
139→                            std::process::exit(1);
140→                        }
141→                    }
142→                }
143→            } else {
144→                // Treat as file glob pattern.
145→                match glob::glob(pattern) {
146→                    Ok(paths) => {
147→                        let mut matched = Vec::new();
148→                        for entry in paths.flatten() {
149→                            if entry.is_file() {
150→                                matched.push(entry);
151→                            } else if entry.is_dir() {
152→                                // Glob matched a directory: expand file
153→                                // globs inside it (non-recursive).
154→                                for fg in &file_globs {
155→                                    let full = format!("{}/{fg}", entry.display());
156→                                    if let Ok(inner) = glob::glob(&full) {
157→                                        for f in inner.flatten() {
158→                                            if f.is_file() {
159→                                                matched.push(f);
160→                                            }
161→                                        }
162→                                    }
163→                                }
164→                            }
165→                        }
166→                        if matched.is_empty() {
167→                            eprintln!("No files match {pattern:?}");
168→                            std::process::exit(1);
169→                        }
170→                        files.extend(matched);
171→                    }
172→                    Err(e) => {
173→                        eprintln!("Bad pattern {pattern:?}: {e}");
174→                        std::process::exit(1);
175→                    }
176→                }
177→            }
178→        }
179→    }
180→
181→    files.sort();
182→    files.dedup();
183→    files
184→}
185→
186→/// Key for grouping errors: the serde error message + record type.
187→#[derive(Hash, Eq, PartialEq)]
188→struct ErrorKey {
189→    message: String,
190→    record_type: String,
191→}
192→
193→/// A single file:line occurrence of an error.
194→struct ErrorHit {
195→    path: String,
196→    line: usize,
197→}
198→
199→/// Tracks one group of identical errors across files.
200→struct ErrorGroup {
201→    count: usize,
202→    /// How many distinct files contain this error.
203→    file_count: usize,
204→    /// Track which files we've seen (by index) to count distinct files.
205→    seen_files: Vec<usize>,
206→    /// All file:line occurrences (one per distinct file).
207→    hits: Vec<ErrorHit>,
208→}
209→
210→fn main() {
211→    let cli = Cli::parse();
212→    let files = resolve_files(&cli);
213→
214→    if files.is_empty() {
215→        eprintln!("No files to process");
216→        std::process::exit(1);
217→    }
218→
219→    let mut total_records: usize = 0;
220→    let mut total_errors: usize = 0;
221→    let mut total_skipped: usize = 0;
222→    let mut total_empty: usize = 0;
223→    let mut skipped_files: Vec<String> = Vec::new();
224→    let mut empty_files: Vec<String> = Vec::new();
225→    let mut error_groups: HashMap<ErrorKey, ErrorGroup> = HashMap::new();
226→    let mut valid_header_printed = false;
227→
228→    for (file_idx, path) in files.iter().enumerate() {
229→        let file = File::open(path).unwrap_or_else(|e| {
230→            eprintln!("Error opening {}: {e}", path.display());
231→            std::process::exit(1);
232→        });
233→
234→        let filename = path
235→            .file_name()
236→            .map(|f| f.to_string_lossy().into_owned())
237→            .unwrap_or_else(|| path.display().to_string());
238→
239→        // Handle .meta.json files as single-object JSON (not JSONL).
240→        if filename.ends_with(".meta.json") {
241→            let metadata = file.metadata().ok();
242→            if metadata.as_ref().is_some_and(|m| m.len() == 0) {
243→                total_empty += 1;
244→                if cli.zero {
245→                    empty_files.push(path.display().to_string());
246→                }
247→                continue;
248→            }
249→            let result: Result<AgentMeta, _> = serde_json::from_reader(file);
250→            match result {
251→                Ok(_meta) => {
252→                    total_records += 1;
253→                    if cli.valid {
254→                        if !valid_header_printed {
255→                            println!("Valid:");
256→                            valid_header_printed = true;
257→                        }
258→                        println!("  {}", path.display());
259→                        println!("    agent-meta (ok)");
260→                    }
261→                }
262→                Err(e) => {
263→                    total_errors += 1;
264→                    let key = ErrorKey {
265→                        message: format!("{e}"),
266→                        record_type: "agent-meta".to_string(),
267→                    };
268→                    let group = error_groups.entry(key).or_insert_with(|| ErrorGroup {
269→                        count: 0,
270→                        file_count: 0,
271→                        seen_files: Vec::new(),
272→                        hits: Vec::new(),
273→                    });
274→                    group.count += 1;
275→                    if !group.seen_files.contains(&file_idx) {
276→                        group.seen_files.push(file_idx);
277→                        group.file_count += 1;
278→                        group.hits.push(ErrorHit {
279→                            path: path.display().to_string(),
280→                            line: 1,
281→                        });
282→                    }
283→                    if cli.valid {
284→                        if !valid_header_printed {
285→                            println!("Valid:");
286→                            valid_header_printed = true;
287→                        }
288→                        println!("  {}", path.display());
289→                        println!("    agent-meta (error)");
290→                    }
291→                }
292→            }
293→            continue;
294→        }
295→
296→        let mut reader = BufReader::new(file);
297→
298→        // Check for empty files before the sniff test.
299→        let mut first_line = String::new();
300→        if reader.read_line(&mut first_line).unwrap_or(0) == 0 {
301→            total_empty += 1;
302→            if cli.zero {
303→                empty_files.push(path.display().to_string());
304→            }
305→            continue;
306→        }
307→
308→        // First-line sniff test: skip .jsonl files that don't look like
309→        // Claude Code sessions. CCS files start with {"type": or {"parentUuid":.
310→        let trimmed = first_line.trim();
311→        if !trimmed.starts_with("{\"type\":") && !trimmed.starts_with("{\"parentUuid\":") {
312→            total_skipped += 1;
313→            if cli.skipped {
314→                skipped_files.push(path.display().to_string());
315→            }
316→            continue;
317→        }
318→
319→        // Process lines starting from the first line we already read.
320→        let mut counts: BTreeMap<&str, usize> = BTreeMap::new();
321→        let mut file_errors: usize = 0;
322→
323→        // Process first line, then remaining lines.
324→        let remaining_lines = reader.lines().map(|l| l.unwrap_or_default());
325→        let all_lines = std::iter::once(first_line.trim_end().to_string()).chain(remaining_lines);
326→
327→        for (i, line) in all_lines.enumerate() {
328→            if line.trim().is_empty() {
329→                continue;
330→            }
331→            match serde_json::from_str::<Record>(&line) {
332→                Ok(record) => {
333→                    *counts.entry(record.label()).or_insert(0) += 1;
334→                }
335→                Err(e) => {
336→                    file_errors += 1;
337→                    let record_type = serde_json::from_str::<serde_json::Value>(&line)
338→                        .ok()
339→                        .and_then(|v| v.get("type")?.as_str().map(String::from))
340→                        .unwrap_or_else(|| "unknown".to_string());
341→
342→                    let key = ErrorKey {
343→                        message: format!("{e}"),
344→                        record_type,
345→                    };
346→                    let group = error_groups.entry(key).or_insert_with(|| ErrorGroup {
347→                        count: 0,
348→                        file_count: 0,
349→                        seen_files: Vec::new(),
350→                        hits: Vec::new(),
351→                    });
352→                    group.count += 1;
353→                    if !group.seen_files.contains(&file_idx) {
354→                        group.seen_files.push(file_idx);
355→                        group.file_count += 1;
356→                        group.hits.push(ErrorHit {
357→                            path: path.display().to_string(),
358→                            line: i + 1,
359→                        });
360→                    }
361→                }
362→            }
363→        }
364→
365→        let file_total: usize = counts.values().sum();
366→        total_records += file_total;
367→        total_errors += file_errors;
368→
369→        if cli.valid {
370→            if !valid_header_printed {
371→                println!("Valid:");
372→                valid_header_printed = true;
373→            }
374→            let mut parts = vec![
375→                format!("errors: {file_errors}"),
376→                format!("records: {file_total}"),
377→            ];
378→            for (label, count) in &counts {
379→                parts.push(format!("{label}: {count}"));
380→            }
381→            println!("  {}", path.display());
382→            println!("    {}", parts.join(", "));
383→        }
384→    }
385→
386→    let file_count = files.len();
387→    let processed = file_count - total_skipped - total_empty;
388→
389→    if valid_header_printed {
390→        println!();
391→    }
392→
393→    let show_errors = cli.errors || cli.error_summary;
394→    if show_errors && !error_groups.is_empty() {
395→        let mut groups: Vec<_> = error_groups.iter().collect();
396→        groups.sort_by(|a, b| b.1.count.cmp(&a.1.count));
397→
398→        if cli.error_summary && cli.errors {
399→            // -e -E combined: grouped summary with all paths nested
400→            println!("Error summary:");
401→            for (key, group) in &groups {
402→                println!("  {}x {} in {}", group.count, key.message, key.record_type,);
403→                for hit in &group.hits {
404→                    println!("    {}:{}", hit.path, hit.line);
405→                }
406→            }
407→            println!();
408→        } else if cli.error_summary {
409→            // -E only: grouped summary, two lines per group
410→            println!("Error summary:");
411→            for (key, group) in &groups {
412→                let first = &group.hits[0];
413→                println!("  {}x {} in {}", group.count, key.message, key.record_type,);
414→                println!(
415→                    "    {} file(s), first: {}:{}",
416→                    group.file_count, first.path, first.line,
417→                );
418→            }
419→            println!();
420→        } else if cli.errors {
421→            // -e only: flat list of all error file:line paths
422→            println!("Errors:");
423→            let mut all_hits: Vec<_> = error_groups.values().flat_map(|g| g.hits.iter()).collect();
424→            all_hits.sort_by(|a, b| a.path.cmp(&b.path).then(a.line.cmp(&b.line)));
425→            for hit in all_hits {
426→                println!("  {}:{}", hit.path, hit.line);
427→            }
428→            println!();
429→        }
430→    }
431→
432→    if cli.skipped && !skipped_files.is_empty() {
433→        println!("Skipped:");
434→        for f in &skipped_files {
435→            println!("  {f}");
436→        }
437→        println!();
438→    }
439→
440→    if cli.zero && !empty_files.is_empty() {
441→        println!("Zero-len:");
442→        for f in &empty_files {
443→            println!("  {f}");
444→        }
445→        println!();
446→    }
447→
448→    let total_files = processed + total_skipped + total_empty;
449→    println!(
450→        "Summary: {total_files} total files, {processed} valid files with {total_records} records, {total_empty} zero-len, {total_skipped} skipped, {total_errors} errors"
451→    );
452→
453→    if cli.strict && total_errors > 0 {
454→        std::process::exit(2);
455→    }
456→}
