                    match glob::glob(&full) {
                        Ok(paths) => {
                            for entry in paths.flatten() {
                                if entry.is_file() {
                                    files.push(entry);
                                }
                            }
                        }
                        Err(e) => {
                            eprintln!("Bad glob {full:?}: {e}");
                            std::process::exit(1);
                        }
                    }
                }
            } else {
                // Treat as file glob pattern.
